Cleanup & Modified

1. Modified the way to initialize vectors "present_kinematic_position_" and "present_joint_angle_" in constructor.

2. Modified the way to copy the values in vector "present_kinematic_position_" in kinematicsPoseCallback.

Actually, I could not build and test with this modified code.

But, when I tested both the previous code and modified code on my test code, the modified code is much faster than the previous code.

The below code is my test code.

```
#include <iostream>
#include <vector>
#include <time.h>

using namespace std;

class vectorTest
{
public:
    vectorTest():positions(3,0){}
    void test0(double x, double y, double z)
    {
        positions = {x, y, z};
    }
    void test1(double x, double y, double z)
    {
        vector<double> temp;
        temp.push_back(x);
        temp.push_back(y);
        temp.push_back(z);

        positions = temp;
    }
private:
    std::vector<double> positions;
};



int main()
{
    vectorTest temp;

    clock_t begin, end;
    begin = clock();

    for (int n = 0; n < 10000000; n++) {
        temp.test0(1.0 , 2.0, 3.0);
    }
    end = clock();
    cout<<"Execution time _test0 : "<<((double)(end-begin)/CLOCKS_PER_SEC)<<endl;

    begin = clock();

    for (int n = 0; n < 10000000; n++) {
        temp.test1(1.0 , 2.0, 3.0);
    }
    end = clock();
    cout<<"Execution time _test1 : "<<((double)(end-begin)/CLOCKS_PER_SEC)<<endl;

    return 0;
}
